"""
MKT Original Commentary — Hebrews chapters 12–13 (gap-fill pass)
Run: python3 scripts/zc-original-hebrews-12-13-gaps.py

Key decisions in this range:
- 12:12 paralelymenas: perfect passive of paralyō — the cognate of our "paralysis"
- 12:15 riza pikrias: Deut 29:17 LXX root of bitterness — insidious underground contamination
- 12:17 metanoias topon: place of repentance vs. place to change the outcome; Esau's irreversibility
- 12:23 pneumasin dikaiōn teteleiōmenōn: spirits not yet in resurrection bodies; made perfect in Christ
- 12:27 metastasis + saleuomena/mē saleuomena: eschatological removal of created order
- 13:5 ou mē...oud' ou mē: double emphatic negation; strongest Greek form
- 13:9 chariti vs. brōmasin: grace stabilizes the heart; food regulations belong to the superseded system
- 13:22 logos tēs paraklēseōs: self-identification of the letter's genre as exhortation/encouragement
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HEBREWS = json.loads(r"""
{
  "12": {
    "3": "<p><strong>analogisasthe gar ton toiautēn hypomenēkota hypo tōn hamartoōlōn eis heauton antilogian</strong> — \"consider him who endured such opposition from sinners against himself, so that you will not grow weary and lose heart\" (<em>analogisasthe</em>: reckon up, consider carefully — aorist imperative of <em>analogizomai</em>: to reason through, to calculate analogically; the <em>ana</em>-prefix suggests careful re-counting): <em>antilogian</em>: contradiction, opposition, hostile speech — <em>anti</em> + <em>logia</em>: speaking-against; the word covers verbal hostility, contradiction, and the formal legal challenge. <em>Kamēte tais psychais hymōn eklyomenoi</em> (lest you become weary, fainting in your souls): <em>eklyō</em>: to release the tension, to go slack — the opposite of the taut focus on Jesus that the verse urges.</p>",
    "6": "<p><strong>hon gar agapāi Kyrios paideuei, mastigoi de panta huion hon paradechetai</strong> — \"because the Lord disciplines the one he loves, and he chastens everyone he accepts as his son\" (Prov 3:12 LXX): <em>mastigoi</em>: scourges, flogs — a stronger word than <em>paideuei</em> (disciplines); the Proverbs text escalates from discipline to scourging to convey the full force of corrective love. <em>Hon agapāi... hon paradechetai</em> (the one he loves... the one he receives/accepts): the divine discipline is restricted to those within the relationship — it is a mark of belonging, not rejection. The parallel structure of the two verbs (discipline/love; scourge/accept) makes the same point twice with different vocabulary.</p>",
    "7": "<p><strong>eis paideian hypomenete; hōs huiois hymin prospheretai ho theos; tis gar huios hon ou paideuei patēr</strong> — \"endure hardship as discipline; God is treating you as his children. For what children are not disciplined by their father?\" (<em>eis paideian hypomenete</em>: endure with a view to/for discipline — the <em>eis</em> gives the purpose: endurance is not mere stoicism but intentional orientation toward the formative goal): <em>hōs huiois hymin prospheretai ho theos</em> (God deals with you as with sons — <em>prospheretai</em>: present tense ongoing dealing): the suffering is not evidence of abandonment but evidence of the Father's engaged parental attention. The rhetorical question (<em>tis gar huios</em>: for what son?) assumes universal affirmative: all sons receive discipline.</p>",
    "8": "<p><strong>ei de chōris este paideias, hēs metochoi gegonasi pantes, ara nothoi kai ouch huioi este</strong> — \"if you are not disciplined — and everyone undergoes discipline — then you are not legitimate children but illegitimate\" (<em>nothoi</em>: illegitimate, bastard-born — a legal term for a child born outside of recognized marriage; <em>ouch huioi</em>: not sons [in the legal sense of recognized, inheriting sons]): the social reality behind the word: a <em>nothos</em> child was not educated by the father and did not share in the father's estate. The absence of discipline signals the absence of the paternal relationship — not divine indifference but non-belonging.</p>",
    "9": "<p><strong>eita tous men tēs sarkos hēmōn pateras eichomen paideutos kai enetrepometha; ou poly mallon hypotakēsometha tō patri tōn pneumatōn kai zēsomen</strong> — \"moreover, we have all had human fathers who disciplined us and we respected them for it. How much more should we submit to the Father of spirits and live\" (<em>pateras tēs sarkos</em>: fathers of the flesh — the bodily, genetic fathers in contrast to <em>ton patera tōn pneumatōn</em> [the Father of spirits]): <em>enetrepometha</em>: we respected, showed deference — <em>entrepō</em>: to turn toward with respect; the <em>a minori ad maius</em> argument: if earthly-biological fathers earned submission through imperfect discipline, the Father whose essence is Spirit and whose discipline is perfect deserves infinitely more. <em>Kai zēsomen</em> (and we will live): submission to the Father of spirits produces life — the submission is not mere social compliance but life-giving covenantal response.</p>",
    "12": "<p><strong>dio tas paralelymenas cheiras kai ta paralyelymena gonata anorthōsate</strong> — \"therefore, strengthen your feeble arms and weak knees\" (Isa 35:3 echoed): <em>paralelymenas cheiras</em>: hands that have been made slack/drooping — <em>paralyelymenas</em>: perfect passive of <em>paralyō</em>: to release the side tension, to go limp; the cognate of our word \"paralysis\": <em>paralelymenas gonata</em> (paralyzed/drooping knees): the two body-parts that fail under sustained exertion — the hands that lose their grip and the knees that buckle. The command is paradoxical: the drooping hands are told to strengthen themselves. The imperatives assume that the community has agency even in exhaustion — the call to action is itself a form of strengthening.</p>",
    "13": "<p><strong>kai trochas orthas poieite tois posin hymōn, hina mē to chōlon ektrapē, iathē de mallon</strong> — \"make level paths for your feet, so that the lame may not be disabled, but rather healed\" (Prov 4:26 echoed; cf. Isa 35:3): <em>trochas orthas poieite</em>: make straight/level tracks — <em>trochias</em>: wheel-tracks, the ruts made by wheels; paths made straight enough for the injured to walk without stumbling. <em>To chōlon</em>: the lame one, the limping member — the community contains members who are weak and close to failing; the stronger members' straight-walking creates the conditions for the weaker to recover rather than collapse. <em>Ektrapē... iathē</em>: be turned aside... be healed — the choice of paths determines the outcome for the vulnerable.</p>",
    "14": "<p><strong>Eirēnēn diōkete meta pantōn kai ton hagiasmon, hou chōris oudeis opsetai ton Kyrion</strong> — \"make every effort to live in peace with everyone and to be holy; without holiness no one will see the Lord\" (<em>diōkete</em>: pursue, chase — the verb of active hunting/pursuit; peace is not a passive condition but an active quest): <em>hagiasmon</em>: sanctification, consecration — the process and state of being set apart; not merely moral improvement but the condition of being appropriately related to the holy God. <em>Hou chōris oudeis opsetai ton Kyrion</em>: without which no one will see the Lord — the eschatological vision of God (the beatific vision) is conditioned on holiness. The warning echoes Ps 24:3-4 (who may stand in the holy place? Those with clean hands and pure hearts).</p>",
    "15": "<p><strong>episkopountes mē tis husterōn apo tēs charitos tou theou, mē tis riza pikrias anō phyousa enochla kai di' autēs mianthōsin hoi polloi</strong> — \"see to it that no one fails to obtain the grace of God and that no bitter root grows up to cause trouble and defile many\" (<em>episkopountes</em>: overseeing, looking over carefully — the community exercise of pastoral mutual-care; <em>husterōn apo tēs charitos</em>: falling short of, falling behind from the grace of God — <em>hysterein apo</em>: to be separated from by falling behind): <em>riza pikrias</em>: root of bitterness (Deut 29:17 LXX): the agricultural metaphor of a poisonous root spreading underground and contaminating what grows from it; bitterness is insidious because it operates beneath the surface and spreads before it is visible. <em>Mianthōsin hoi polloi</em>: the many be defiled — the singular root affects the corporate community.</p>",
    "16": "<p><strong>mē tis pornos ē bebēlos hōs Ēsau, hos anti brōseōs mias apedeto ta prōtotokia heautou</strong> — \"see that no one is sexually immoral, or is godless like Esau, who for a single meal sold his inheritance rights as the oldest son\" (<em>bebēlos</em>: profane, godless — one who crosses into the sacred realm with improper foot, who treats what is set-apart as common; <em>brōseōs mias</em>: a single eating/meal — <em>brōsis</em>: the eating-act, food): Esau is paired with pornos (sexually immoral) not because the two sins are equated but because both represent the exchange of the permanent for the immediate-sensory. <em>Prōtotokia</em>: birthright, firstborn privileges — the entire future inheritance-claim exchanged for a bowl of stew. The sacrilege (<em>bebēlos</em>) is the measure by which Hebrews frames Esau: not sexual but covenantal failure.</p>",
    "17": "<p><strong>iste gar hoti kai metepeita thelōn klēronomēsai tēn eulogian apedokimasthē, metanoias gar topon ouch heuren, kaitoi meta dakryon ekzētēsas autēn</strong> — \"for you know that afterward, when he wanted to inherit the blessing, he was rejected. Even though he sought the blessing with tears, he could not change what he had done\" (<em>apedokimasthē</em>: was rejected — aorist passive of <em>apodokimazō</em>: to reject after testing, to pronounce unfit; cf. the rejected stone of Ps 118:22): <em>metanoias topon ouch heuren</em>: found no place of repentance — the phrase is ambiguous: did he find no place to repent, or did he find no place to change the outcome? The Greek <em>metanoia</em> can mean either. In context, the <em>topon</em> (place) likely means the opportunity to reverse the outcome — the irreversibility of the birthright transaction is the pastoral warning.</p>",
    "19": "<p><strong>kai salpiggos ēchō kai phōnē rhēmatōn, hēs hoi akousantes parētēsanto mē prostethēnai autois logon</strong> — \"to the blast of a trumpet and to such a voice speaking words that those who heard it begged that no further word be spoken to them\" (<em>salpingos ēchō</em>: the sound of a trumpet — Sinai's characteristic soundscape [Exod 19:16, 19]): <em>parētēsanto</em>: begged off, asked to be excused — <em>paraiteomai</em>: to ask to be removed from something, to excuse oneself; the same verb as 12:25 (do not refuse him who speaks). The people at Sinai could not bear the weight of direct divine address — their refusal is not disobedience but the recognition of creaturely incapacity before unmediated divine speech.</p>",
    "20": "<p><strong>ouk epheron gar to diastelloumenon, Kan thērion thigē tou orous, lithobolēthēsetai</strong> — \"because they could not bear what was commanded: If even an animal touches the mountain, it must be stoned\" (Exod 19:12-13): <em>ouk epheron</em>: they could not bear/carry — the weight of the divine command was unbearable; <em>to diastelloumenon</em>: what was commanded/ordered — the present passive participle of <em>diasstellō</em>: to command definitively, to give decisive orders. <em>Kan thērion thigē</em>: even if a beast touches — the most minimal, innocent contact with the mountain incurred capital punishment for the animal; the holiness-gradient at Sinai was absolute and death-dealing.</p>",
    "21": "<p><strong>kai houtōs phoberotaton ēn to phantazomenon, Mōysēs eipen, Ekphobos eimi kai entromos</strong> — \"the sight was so terrifying that Moses said, I am trembling with fear\" (<em>phoberotaton ēn to phantazomenon</em>: the spectacle was absolutely terrifying — <em>phoberōtatos</em> is the superlative of <em>phoberos</em>: the most terrifying possible; <em>phantazomenon</em>: the appearing, the thing made visible — the theophanic spectacle): <em>Ekphobos eimi kai entromos</em>: I am struck with terror and trembling — the two compounds (<em>ek</em>-phobos: terror-struck; <em>en</em>-tromos: shaking-inwardly) together convey total physical and psychological overwhelm. The attribution to Moses of words from the Sinai theophany combines Deut 9:19 (Moses's fear at the golden-calf incident) with the Sinai context — a free composite citation.</p>",
    "23": "<p><strong>ekklēsia prōtotokōn apographomenōn en ouranois, kai kritē theō pantōn, kai pneumasin dikaiōn teteleiōmenōn</strong> — \"to the assembly of the firstborn, whose names are written in heaven. You have come to God, the Judge of all, to the spirits of the righteous made perfect\" (<em>prōtotokōn apographomenōn</em>: of firstborn ones enrolled — <em>apographō</em>: to register, to enroll in a public census or citizenship list; the heavenly enrollment is the eschatological citizenship registration): <em>ekklēsia prōtotokōn</em>: the assembly of the firstborn — the plural <em>prōtotokōn</em> extends the firstborn status (held uniquely by the Son) to all who share in Christ's inheritance. <em>Pneumasin dikaiōn teteleiōmenōn</em>: spirits of the righteous who have been made perfect — the OT saints of ch11 now perfected in Christ (cf. 11:40); they are <em>pneumata</em> (spirits) because their resurrection bodies are still awaited.</p>",
    "25": "<p><strong>Blepete mē paraitēsēsthe ton lalounta; ei gar ekeinoi ouk exephygon epi gēs paraitēsamenoi ton chrēmatizonta, poly mallon hēmeis hoi ton ap' ouranōn apostraphentes</strong> — \"see to it that you do not refuse him who speaks. If they did not escape when they refused him who warned them on earth, how much less will we, if we turn away from him who warns us from heaven\" (<em>paraitēsēsthe</em>: refuse, beg off — aorist subjunctive; the same word used in v19 for Israel's refusal at Sinai): the structure is the familiar <em>a minori ad maius</em> argument: if the earthly theophany's rejection was fatal, the heavenly one's rejection is infinitely more so. <em>Ton chrēmatizonta</em>: the one who divinely warned — <em>chrēmatizō</em>: to receive a divine oracle, to be divinely instructed (cf. 8:5 of Moses). <em>Ap' ouranōn apostraphentes</em>: those turning away from heaven — the turn-away is directional, leaving the heavenly voice behind.</p>",
    "26": "<p><strong>hou hē phōnē tēn gēn esaleusen tote, nyn de epēggeltai legōn, Eti hapax egō seiō ou monon tēn gēn alla kai ton ouranon</strong> — \"at that time his voice shook the earth, but now he has promised: Once more I will shake not only the earth but also the heavens\" (Hag 2:6 LXX): <em>esaleusen</em>: shook — aorist; the Sinai earth-shaking is past and completed. <em>Eti hapax</em>: yet once more — the eschatological shaking is introduced by <em>eti hapax</em>: not a repeated event in the Sinai series but a final definitive shaking that goes beyond the earth to the heavens. <em>Ou monon... alla kai</em> (not only... but also): the scope of the coming shaking exceeds all previous ones — both created realms are shaken.</p>",
    "27": "<p><strong>to de Eti hapax dēloi tēn tōn saleuomenōn metastasin hōs pepoiēmenōn, hina meinē ta mē saleuomena</strong> — \"the words 'once more' indicate the removing of what can be shaken — that is, created things — so that what cannot be shaken may remain\" (<em>metastasin</em>: removal, translation, transformation — from <em>methistēmi</em>: to remove, transfer, displace; a NT word for both physical removal and metaphorical transformation): <em>tōn saleuomenōn</em> vs. <em>ta mē saleuomena</em>: the shakeable vs. the unshakeable — the contrast structures the eschatological hermeneutic. <em>Hōs pepoiēmenōn</em> (as having been made — perfect passive participle): that which was made/created is by nature shakeable because it was made at a point in time from nothing. What was not made (the kingdom of v28) cannot be shaken because it does not belong to the created order.</p>"
  },
  "13": {
    "1": "<p><strong>Hē philadelphia menetō</strong> — \"let brotherly love continue\" (<em>philadelphia</em>: love of brothers — <em>philos</em> [affection/friendship-love] + <em>adelphos</em> [brother]; the compound covers the warm, familial bond of the community): <em>menetō</em>: let it remain, let it continue — present imperative of <em>menō</em>: to stay, to abide; the call is not to establish what is new but to maintain what already exists. The word choice <em>philadelphia</em> rather than <em>agapē</em> is notable — the sibling-affection word is appropriate for a community whose members are the <em>adelphoi</em> (brothers and sisters) of the Son who is not ashamed to call them such (2:11-12).</p>",
    "3": "<p><strong>mimnēskesthe tōn desmion hōs syndedemenoi, tōn kakouchoumenōn hōs kai autoi ontes en sōmati</strong> — \"remember those who are in prison as if you were their fellow prisoners, and those who are mistreated as if you yourselves were suffering\" (<em>hōs syndedemenoi</em>: as if bound-together-with — <em>syndesmoi</em>: co-prisoners; the <em>syn</em>-prefix expresses the imaginative solidarity): <em>hōs kai autoi ontes en sōmati</em>: as yourselves also being in the body — <em>en sōmati</em>: the bodily existence that makes suffering real and shareable; the reminder that the community shares the same physical vulnerability. The identification is not merely empathetic but bodily — the same flesh is the site of both comfort and suffering.</p>",
    "4": "<p><strong>Timios ho gamos en pasin kai hē koitē amiantos; pornous gar kai moichous krinei ho theos</strong> — \"let marriage be held in honor by all, and let the marriage bed be kept pure, for God will judge the sexually immoral and the adulterous\" (<em>timios</em>: honored, precious — the same word for \"precious\" in 1 Pet 1:19 of Christ's blood): <em>koitē amiantos</em>: undefiled bed — <em>koitē</em>: the marriage bed as a metonymy for the sexual relationship; <em>amiantos</em>: unstained, same word as 7:26 for Christ as unstained. <em>Pornous kai moichous krinei ho theos</em>: God judges the sexually immoral and the adulterous — present tense: the divine judgment is ongoing and certain; <em>pornos</em> (one who practices sexual immorality) and <em>moichos</em> (adulterer, one who violates the marriage covenant) cover both pre-marital and extra-marital violations.</p>",
    "5": "<p><strong>Aphilēargyros ho tropos; arkoumenoi tois parousin; autos gar eirēken, Ou mē se anō oud' ou mē se egkataleipō</strong> — \"keep your life free from love of money, and be content with what you have, for he has said: Never will I leave you; never will I forsake you\" (<em>aphilēargyros ho tropos</em>: let your manner of life be free from love of silver/money — <em>a</em>-privative + <em>philos</em> + <em>argyros</em>: the compound adjective; <em>tropos</em>: manner of life, disposition): <em>Ou mē se anō oud' ou mē se egkataleipō</em>: the double negative <em>ou mē</em> used twice, the strongest possible Greek negation, translating a Hebrew emphatic promise (Josh 1:5; Deut 31:6, 8): the divine promise of non-abandonment is given as the logical ground for the contentment-command — one who holds the divine promise of presence has no rational basis for anxious acquisitiveness.</p>",
    "6": "<p><strong>hōste tharroūntas hēmas legein, Kyrios emoi boēthos, [kai] ou phobēthēsomai; ti poiēsei moi anthrōpos</strong> — \"so we say with confidence: The Lord is my helper; I will not be afraid. What can anyone do to me?\" (Ps 118:6 LXX): <em>tharroūntas</em>: having confidence, being bold — present active participle of <em>tharreō</em>: to be bold, to take courage; the confidence produces the declaration. <em>Boēthos</em>: helper, one who runs to the cry (cf. 2:18: <em>boēthēsai</em>) — the divine title echoes the high-priestly help of the earlier chapters. <em>Ti poiēsei moi anthrōpos</em>: what shall a human being do to me? — <em>anthrōpos</em> here is the mortal human in contrast to the divine Helper; the rhetorical question assumes the answer: nothing that matters ultimately.</p>",
    "9": "<p><strong>didachais poikilais kai xenais mē parapheresthe; kalon gar chariti bebaiouesthai tēn kardian, ou brōmasin, en hois ouk ōphelēthēsan hoi peripatountes</strong> — \"do not be carried away by all kinds of strange teachings. It is good for the heart to be strengthened by grace, not by food regulations, which are of no benefit to those who observe them\" (<em>didachais poikilais kai xenais</em>: various and foreign teachings — <em>poikilos</em>: many-colored, varied, diverse; <em>xenos</em>: foreign, strange, belonging to another tradition; the combination signals novelty and foreignness): <em>parapheresthe</em>: do not be carried away/swept along — the nautical image recurs (cf. 2:1, pararrōmen); <em>chariti</em>: by grace — the contrast between <em>charis</em> and <em>brōmata</em> (foods) is the theological point: what stabilizes the heart is grace (the new covenant gift), not the observance of dietary regulations whose ritual significance has been superseded.</p>",
    "11": "<p><strong>hōn gar eisipheretai zōōn to haima peri hamartias eis ta hagia dia tou archiereōs, toutōn ta sōmata katakaietai exō tēs parembolas</strong> — \"for the bodies of those animals whose blood is brought into the Most Holy Place by the high priest as a sin offering are burned outside the camp\" (Lev 16:27): <em>exō tēs parembolas</em>: outside the camp — the Levitical sin-offering whose blood entered the sanctuary had its carcass burned outside the camp (not consumed); the blood went in, the body went out. <em>Parembola</em>: camp — the word for the Israelite wilderness camp; Hebrews uses it deliberately to frame the typology in Mosaic terms before applying it to Christ's crucifixion outside Jerusalem's gate (v12).</p>",
    "13": "<p><strong>toinun exerchōmetha pros auton exō tēs parembolas, ton oneidismon autou pherontes</strong> — \"let us, then, go to him outside the camp, bearing the disgrace he bore\" (<em>toinun exerchōmetha</em>: therefore let us go out — the inferential particle <em>toinun</em> introduces the application drawn from the typology; <em>exerchōmetha</em>: hortatory subjunctive: the author includes himself in the call): <em>exō tēs parembolas</em> (outside the camp): the spatial movement required of the community — going out from the security of the religious establishment that crucified Christ and joining him in the social margins. <em>Ton oneidismon autou pherontes</em>: bearing his disgrace/reproach — the same <em>oneidismos</em> that Moses bore (11:26); the reproach is not incidental to the journey but its content.</p>",
    "14": "<p><strong>ou gar echomen hōde menousan polin, alla tēn mellousan epizētoumen</strong> — \"for here we do not have an enduring city, but we are looking for the city that is to come\" (<em>menousan polin</em>: an abiding/remaining city — <em>menousa</em>: present participle of <em>menō</em>: the city that remains, the permanent city): the city-language binds together the entire letter's climax: the patriarchs looked for a city (11:10, 16), Mount Zion is the heavenly Jerusalem (12:22), and the community has no permanent earthly city. <em>Tēn mellousan</em>: the coming one — the same <em>mellō</em> root as the coming age, the coming good things; the community's citizenship is in the city that is still arriving.</p>",
    "16": "<p><strong>tēs de eupoiias kai koinōnias mē epilanthanethe; toiautais gar thysiais euaresteitai ho theos</strong> — \"and do not forget to do good and to share with others, for with such sacrifices God is pleased\" (<em>eupoiia</em>: doing good, beneficence — <em>eu</em> + <em>poieō</em>: the compound for well-doing; a NT hapax): <em>koinōnias</em>: sharing, fellowship — the economic and social solidarity of the community. <em>Toiautais thysiais</em>: with such sacrifices — the vocabulary of sacrifice is applied to concrete acts of generosity; the sacrificial system has not simply ended but been transformed: the offerings God receives now are praise (v15) and beneficence (v16). The two new-covenant sacrifices match the old covenant's two dimensions: the upward offering to God (praise) and the horizontal sharing with others.</p>",
    "17": "<p><strong>Peithesthe tois hēgoumenois hymōn kai hypeikete; autoi gar agrypnousin hyper tōn psychōn hymōn hōs logon apodōsontes</strong> — \"have confidence in your leaders and submit to their authority, because they keep watch over you as those who must give an account\" (<em>agrypnousin</em>: they keep watch, lie awake for — present tense: the ongoing watchfulness; <em>agrypneō</em>: to be sleepless, to lie awake watching; the image of a shepherd who cannot sleep while the flock is in danger): <em>hōs logon apodōsontes</em>: as those about to give an account — <em>apodidōmi</em>: to give back, to render; the account is rendered to God, not to the community. The leaders' accountability to God is both the ground of their authority and the limit of it. <em>Hina meta charas touto poiōsin kai mē stenazontes</em>: so that they do this with joy and not with groaning.</p>",
    "18": "<p><strong>Proseuchesthe peri hēmōn; peithometha gar hoti kalēn syneidēsin echomen</strong> — \"pray for us. We are sure that we have a clear conscience and desire to live honorably in every way\" (<em>kalēn syneidēsin</em>: a beautiful/good conscience — <em>kalos</em>: good in the qualitative sense of beauty and excellence; the <em>syneidēsis</em> [conscience] that the sprinkled blood of Christ has cleansed [9:14] is now described as <em>kalē</em>): <em>en pasin kalōs thelontes anastraphēnai</em>: desiring to conduct ourselves well in all things — <em>anastraphēnai</em>: to conduct oneself, to live; the conscience claim is accompanied by the desire for corresponding conduct. The prayer-request grounds the author's pastoral authority in personal integrity.</p>",
    "19": "<p><strong>perissoteros de parakalō touto poiēsai, hina tachion apokatastathō hymin</strong> — \"I particularly urge you to pray so that I may be restored to you soon\" (<em>perissoteros parakalō</em>: I urge more abundantly/especially — the superlative adverb intensifying the urgency): <em>apokatastathō</em>: be restored — aorist passive subjunctive of <em>apokathistēmi</em>: to restore fully to the original position; the same verb for eschatological restoration. <em>Tachion</em>: more quickly, sooner — comparative of <em>tachus</em>: the author's desire is for an expedited reunion. The personal note grounds the theological treatise in an actual relationship between author and community.</p>",
    "21": "<p><strong>katartisai hymas en panti agathō eis to poiēsai to thelēma autou, poiōn en hēmin to euareston enōpion autou dia Iēsou Christou</strong> — \"equip you with everything good for doing his will, and may he work in us what is pleasing to him, through Jesus Christ\" (<em>katartisai</em>: equip, restore, fit out — the same verb as 10:5 [body you prepared/fitted] and Eph 4:12 [equipping of the saints]): <em>to euareston</em>: what is pleasing, the pleasing thing — the verbal noun captures the quality of divine approval; <em>poiōn en hēmin</em>: working in us — God is the agent of both the equipping and the performing; the prayer acknowledges that the doing of God's will is itself a divine work within the community. <em>Dia Iēsou Christou</em>: through Jesus Christ — the mediatorial channel of all divine working.</p>",
    "22": "<p><strong>Parakalō de hymas, adelphoi, anechesthe tou logou tēs paraklēseōs, kai gar dia bracheōn epestila hymin</strong> — \"brothers and sisters, I urge you to bear with my word of exhortation, for in fact I have written to you quite briefly\" (<em>logou tēs paraklēseōs</em>: word of exhortation/encouragement — <em>paraklēsis</em>: the calling-alongside to encourage, strengthen, or exhort; a self-identification of the letter's genre): <em>dia bracheōn epestila</em>: I wrote through brief/short means — <em>dia bracheōn</em>: briefly, concisely; the author is aware that what the community might find difficult to receive has been presented as briefly as possible. The letter is long by NT standards; \"briefly\" is relative to the depth of the material covered.</p>",
    "23": "<p><strong>ginōskete ton adelphon Timotheon apolelumenon, meth' hou, ean tachion erchētai, opsōmai hymas</strong> — \"I want you to know that our brother Timothy has been released. If he arrives soon, I will come with him to see you\" (<em>apolelumenon</em>: having been released — perfect passive participle of <em>apoluō</em>: to release, set free; the same word for releasing from prison or for the Levitical dismissal): the mention of Timothy (<em>ton adelphon Timotheon</em>: the brother Timothy) and his release from some form of custody provides the one unambiguous personal identification in the letter. The conditional <em>ean tachion erchētai</em> (if he arrives soon enough) ties the author's intended visit to Timothy's freedom of travel.</p>",
    "24": "<p><strong>Aspasasthe pantas tous hēgoumenous hymōn kai pantas tous hagious; aspazontai hymas hoi apo tēs Italias</strong> — \"greet all your leaders and all the Lord's people. Those from Italy send you their greetings\" (<em>Aspasasthe</em>: greet — the standard epistolary closing formula): <em>pantas... pantas</em> (all... all): the double <em>pantas</em> emphasizes comprehensiveness — no leader and no holy person is excluded from the greeting. <em>Hoi apo tēs Italias</em>: those from Italy — a phrase that can mean either those currently in Italy (writing to the recipients) or Italian expatriates who are with the author and send greetings back home; the latter reading supports the hypothesis of Roman recipients.</p>",
    "25": "<p><strong>Hē charis meta pantōn hymōn</strong> — \"grace be with you all\" (<em>Hē charis</em>: the grace — with the article: a specific grace, the grace of the Lord Jesus Christ): the minimal epistolary benediction. <em>Meta pantōn hymōn</em>: with all of you — the <em>pantōn</em> echoes the universal scope of the greeting in v24; the closing grace encompasses the entire community. <em>Charis</em> as the closing word gathers the theological heart of the letter: the grace mediated by the eternal high priest who entered once for all into the heavenly sanctuary is the final word to the community that is called to draw near with confidence.</p>"
  }
}
""")

def main():
    existing = load_comm("mkt-original", "hebrews")
    merge_comm(existing, HEBREWS)
    save_comm("mkt-original", "hebrews", existing)
    total = sum(len(v) for v in existing.values())
    print(f"Hebrews 12-13 mkt-original gaps filled: {len(existing)} chapters, {total} verses written.")

if __name__ == "__main__":
    main()
